INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('technology_software_engineer', 'Technology', 'Software Engineer', 'I am writing to express my strong interest in the {role_type} position at {company_name}. As a {years}-year military veteran with extensive experience in {domain}, I bring a unique combination of leadership, discipline, and technical expertise that directly aligns with your team''s needs.', 'During my military service, I managed complex IT infrastructure supporting {user_count}+ users across multiple locations. I led teams of {team_size} technicians in maintaining {uptime}% system availability while implementing security protocols that protected classified networks. My experience with {tech_stack} and enterprise systems administration translates directly to your technology environment.', 'Beyond technical qualifications, my military experience has developed exceptional soft skills that are critical in any organization. I am adept at building high-performing teams, communicating complex information to diverse audiences, and maintaining composure under pressure. I bring a strong work ethic, unwavering integrity, and a commitment to continuous improvement that will add immediate value to your organization.', 'I would welcome the opportunity to discuss how my military experience and skills can contribute to {company_name}''s success. I am available for an interview at your convenience and can be reached at {phone} or {email}. Thank you for considering my application, and I look forward to the possibility of joining your team.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Technology Software Engineer roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('technology_it_manager', 'Technology', 'IT Manager', 'With {years} years of proven leadership and operational excellence in the {branch}, I am excited to apply for the {role_type} role at {company_name}. My military career has equipped me with the skills, resilience, and results-driven mindset that {company_name} values.', 'In my role as {military_title}, I led the implementation of {technology} across a {scope}-person organization, resulting in {result}. I am experienced in {tech_stack} and hold certifications including {certifications}. My ability to bridge technical depth with strategic communication ensures I can contribute both as an individual contributor and team leader.', 'What sets me apart is not just my technical background but the leadership philosophy I developed through military service. I believe in servant leadership, accountability, and empowering team members to achieve their full potential. I have consistently built teams that exceed expectations, and I am eager to bring this approach to {company_name}.', 'Thank you for considering my application for the {role_type} position. I am confident that my {years} years of military leadership and operational experience make me a strong candidate. I welcome the opportunity to discuss how I can contribute to {company_name}''s mission and would be happy to provide additional references or information upon request.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Technology IT Manager roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('technology_systems_administrator', 'Technology', 'Systems Administrator', 'I am eager to bring my {years} years of military experience to the {role_type} position at {company_name}. My background in {domain} has prepared me to deliver immediate value in a fast-paced civilian environment.', 'During my military service, I managed complex IT infrastructure supporting {user_count}+ users across multiple locations. I led teams of {team_size} technicians in maintaining {uptime}% system availability while implementing security protocols that protected classified networks. My experience with {tech_stack} and enterprise systems administration translates directly to your technology environment.', 'My military training has instilled in me a deep appreciation for teamwork, planning, and execution. I am accustomed to working in environments where precision matters, deadlines are non-negotiable, and adaptability is essential. These qualities, combined with my commitment to professional development and continuous learning, make me a strong addition to your team.', 'I am enthusiastic about the opportunity to bring my military-honed skills to {company_name} and am confident I can make an immediate impact. I would appreciate the chance to discuss my qualifications in more detail. Please feel free to contact me at {phone} or {email} to schedule a conversation.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related