INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('government_program_analyst', 'Government', 'Program Analyst', 'I am writing to express my strong interest in the {role_type} position at {company_name}. As a {years}-year military veteran with extensive experience in {domain}, I bring a unique combination of leadership, discipline, and technical expertise that directly aligns with your team''s needs.', 'My {years} years of federal service have given me deep experience in government operations, policy development, and interagency coordination. I have managed programs with budgets exceeding ${budget}, led cross-functional teams, and maintained security clearances at the {clearance_level} level. I understand the unique demands of public sector work and am ready to contribute immediately.', 'Beyond technical qualifications, my military experience has developed exceptional soft skills that are critical in any organization. I am adept at building high-performing teams, communicating complex information to diverse audiences, and maintaining composure under pressure. I bring a strong work ethic, unwavering integrity, and a commitment to continuous improvement that will add immediate value to your organization.', 'I would welcome the opportunity to discuss how my military experience and skills can contribute to {company_name}''s success. I am available for an interview at your convenience and can be reached at {phone} or {email}. Thank you for considering my application, and I look forward to the possibility of joining your team.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Government Program Analyst roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('government_policy_advisor', 'Government', 'Policy Advisor', 'With {years} years of proven leadership and operational excellence in the {branch}, I am excited to apply for the {role_type} role at {company_name}. My military career has equipped me with the skills, resilience, and results-driven mindset that {company_name} values.', 'Throughout my career, I served in roles requiring strategic analysis, stakeholder management, and complex project execution. I held a {clearance_level} security clearance and regularly briefed senior leaders on operational readiness and policy recommendations. My understanding of federal acquisition, compliance frameworks, and organizational management directly supports this role.', 'What sets me apart is not just my technical background but the leadership philosophy I developed through military service. I believe in servant leadership, accountability, and empowering team members to achieve their full potential. I have consistently built teams that exceed expectations, and I am eager to bring this approach to {company_name}.', 'Thank you for considering my application for the {role_type} position. I am confident that my {years} years of military leadership and operational experience make me a strong candidate. I welcome the opportunity to discuss how I can contribute to {company_name}''s mission and would be happy to provide additional references or information upon request.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Government Policy Advisor roles') ON CONFLICT DO NOTHING;
