INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('logistics_transportation_director', 'Logistics', 'Transportation Director', 'With {years} years of proven leadership and operational excellence in the {branch}, I am excited to apply for the {role_type} role at {company_name}. My military career has equipped me with the skills, resilience, and results-driven mindset that {company_name} values.', 'As a {military_title}, I directed logistics operations for a {scope}-person organization across multiple locations. I managed ${value}+ in assets, achieved {metric}% on-time delivery rates, and implemented inventory management systems that eliminated waste. My experience directly translates to the supply chain excellence {company_name} requires.', 'What sets me apart is not just my technical background but the leadership philosophy I developed through military service. I believe in servant leadership, accountability, and empowering team members to achieve their full potential. I have consistently built teams that exceed expectations, and I am eager to bring this approach to {company_name}.', 'Thank you for considering my application for the {role_type} position. I am confident that my {years} years of military leadership and operational experience make me a strong candidate. I welcome the opportunity to discuss how I can contribute to {company_name}''s mission and would be happy to provide additional references or information upon request.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Logistics Transportation Director roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('logistics_warehouse_manager', 'Logistics', 'Warehouse Manager', 'I am eager to bring my {years} years of military experience to the {role_type} position at {company_name}. My background in {domain} has prepared me to deliver immediate value in a fast-paced civilian environment.', 'My military logistics experience includes managing supply chains with {line_items}+ line items valued at ${value}+, coordinating transportation across multiple modes, and achieving {accuracy}% inventory accuracy. I led teams of {team_size} logistics professionals and implemented process improvements that reduced order fulfillment time by {reduction}%.', 'My military training has instilled in me a deep appreciation for teamwork, planning, and execution. I am accustomed to working in environments where precision matters, deadlines are non-negotiable, and adaptability is essential. These qualities, combined with my commitment to professional development and continuous learning, make me a strong addition to your team.', 'I am enthusiastic about the opportunity to bring my military-honed skills to {company_name} and am confident I can make an immediate impact. I would appreciate the chance to discuss my qualifications in more detail. Please feel free to contact me at {phone} or {email} to schedule a conversation.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civil